import base64
import logging
from django.contrib.auth import login
from django.contrib.auth.models import User
from django.http import HttpResponse
from django.views.decorators.csrf import csrf_exempt
from django.views import View
from lxml import etree
from datetime import datetime
from dateutil import parser as date_parser

logger = logging.getLogger(__name__)

class SAMLResponseView(View):
    @csrf_exempt
    def post(self, request, *args, **kwargs):
        saml_response = request.POST.get('SAMLResponse')
        if not saml_response:
            return HttpResponse('No SAML Response', status=400)

        try:
            decoded_response = base64.b64decode(saml_response)
            xml_tree = etree.fromstring(decoded_response)
        except Exception as e:
            logger.error(f"Failed to decode or parse SAML response: {e}")
            return HttpResponse('Invalid SAML Response', status=400)

        if not self.validate_xml_structure(xml_tree):
            return HttpResponse('Invalid XML Structure', status=400)

        if not self.validate_timestamps(xml_tree):
            return HttpResponse('SAML Response is not valid due to timestamp issues', status=400)

        user_info = self.extract_user_info(xml_tree)
        if not user_info:
            return HttpResponse('Failed to extract user information', status=400)

        user = self.get_or_create_user(user_info)
        login(request, user)
        return HttpResponse('Login successful')

    def validate_xml_structure(self, xml_tree):
        try:
            # Basic structure validation
            assertion = xml_tree.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}Assertion')
            if assertion is None:
                return False
            return True
        except Exception as e:
            logger.error(f"XML structure validation error: {e}")
            return False

    def validate_timestamps(self, xml_tree):
        try:
            conditions = xml_tree.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}Conditions')
            if conditions is not None:
                not_before = conditions.get('NotBefore')
                not_on_or_after = conditions.get('NotOnOrAfter')
                current_time = datetime.utcnow()

                if not_before and date_parser.parse(not_before) > current_time:
                    return False
                if not_on_or_after and date_parser.parse(not_on_or_after) <= current_time:
                    return False
            return True
        except Exception as e:
            logger.error(f"Timestamp validation error: {e}")
            return False

    def extract_user_info(self, xml_tree):
        try:
            name_id = xml_tree.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}NameID').text
            attributes = {}
            attribute_elements = xml_tree.findall('.//{urn:oasis:names:tc:SAML:2.0:assertion}Attribute')
            for attribute in attribute_elements:
                attr_name = attribute.get('Name')
                attr_value = attribute.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}AttributeValue').text
                attributes[attr_name] = attr_value
            return {'name_id': name_id, 'attributes': attributes}
        except Exception as e:
            logger.error(f"Error extracting user info: {e}")
            return None

    def get_or_create_user(self, user_info):
        name_id = user_info['name_id']
        attributes = user_info['attributes']
        user, created = User.objects.get_or_create(username=name_id)
        if created:
            user.first_name = attributes.get('FirstName', '')
            user.last_name = attributes.get('LastName', '')
            user.email = attributes.get('Email', '')
            user.save()
        return user